func main() {
	cfg := loadConfig()
	app := NewApp(cfg)
	app.startupSelfCheck()

	if cfg.RenderExternalURL != "" {
		go app.keepAliveLoop()
	}
	if cfg.TelegramBotToken != "" && cfg.TelegramPolling {
		go app.telegramPollingLoop(context.Background())
	}
	go app.schedulerLoop(context.Background())

	mux := http.NewServeMux()
	app.registerRoutes(mux)

	srv := &http.Server{
		Addr:              ":" + cfg.Port,
		Handler:           app.securityMiddleware(mux),
		ReadHeaderTimeout: 15 * time.Second,
		ReadTimeout:       90 * time.Second,
		WriteTimeout:      120 * time.Second,
		IdleTimeout:       120 * time.Second,
	}
	log.Printf("Go bot/admin server listening on :%s", cfg.Port)
	if err := srv.ListenAndServe(); err != nil && !errors.Is(err, http.ErrServerClosed) {
		log.Fatal(err)
	}
}

func loadConfig() Config {
	locName := envStr("APP_TIMEZONE", envStr("WEB_ADMIN_TIMEZONE", "Asia/Phnom_Penh"))
	loc, err := time.LoadLocation(locName)
	if err != nil {
		loc = time.FixedZone("ICT", 7*3600)
	}
	ids := parseAdminIDs(envStr("ADMIN_IDS", ""))
	list := make([]int64, 0, len(ids))
	for id := range ids {
		list = append(list, id)
	}
	sort.Slice(list, func(i, j int) bool { return list[i] < list[j] })

	secret := envStr("FLASK_SECRET_KEY", envStr("WEB_SECRET_KEY", ""))
	if secret == "" {
		secret = randomToken(32)
	}

	return Config{
		Port:                   envStr("PORT", "8080"),
		RenderExternalURL:      strings.TrimRight(envStr("RENDER_EXTERNAL_URL", ""), "/"),
		WebAdminEnabled:        envBool("WEB_ADMIN_ENABLED", true),
		WebAdminPassword:       firstNonEmpty(envStr("ADMIN_WEB_PASSWORD", ""), envStr("WEB_ADMIN_PASSWORD", "")),
		WebSessionCookie:       envStr("WEB_SESSION_COOKIE_NAME", "bot_admin_session"),
		WebSecret:              secret,
		WebCookieSecure:        envBool("WEB_COOKIE_SECURE", false),
		AdminIDs:               ids,
		AdminIDList:            list,
		TelegramBotToken:       envStr("TELEGRAM_BOT_TOKEN", envStr("BOT_TOKEN", "")),
		TelegramPolling:        envBool("TELEGRAM_POLLING", true),
		TelegramWebhookSecret:  envStr("TELEGRAM_WEBHOOK_SECRET", ""),
		SupabaseURL:            strings.TrimRight(envStr("SUPABASE_URL", ""), "/"),
		SupabaseKey:            firstNonEmpty(envStr("SUPABASE_SERVICE_ROLE_KEY", ""), envStr("SUPABASE_KEY", "")),
		RedisURL:               envStr("REDIS_URL", ""),
		HFToken:                envStr("HF_TOKEN", ""),
		HFModel:                envStr("HF_MODEL", "Qwen/Qwen2.5-7B-Instruct"),
		HFOCRModel:             envStr("HF_OCR_MODEL", "lkhapple/Khmer-TrOCR-OCR"),
		AIProvider:             strings.ToLower(envStr("AI_PROVIDER", "hf")),
		OCRProvider:            strings.ToLower(envStr("OCR_PROVIDER", "auto")),
		GeminiAPIKey:           envStr("GEMINI_API_KEY", ""),
		GeminiModel:            envStr("GEMINI_MODEL", "gemini-2.5-flash"),
		MaxConcurrentBroadcast: envInt("MAX_CONCURRENT_BROADCAST", 3, 1, 200),
		BroadcastBatchSize:     envInt("BROADCAST_BATCH_SIZE", envInt("MAX_CONCURRENT_BROADCAST", 3, 1, 200), 1, 500),
		BroadcastDelay:         time.Duration(envFloat("BROADCAST_INTER_BATCH_DELAY", 0.20) * float64(time.Second)),
		AppLocation:            loc,
		TimezoneName:           locName,
		TimezoneAlias:          envStr("APP_TIMEZONE_ALIAS", "ICT"),
		TimezoneUTCLabel:       envStr("APP_TIMEZONE_UTC_LABEL", "UTC+7"),
		EdgeTTSBin:             envStr("EDGE_TTS_BIN", "edge-tts"),
		FFMpegBin:              envStr("FFMPEG_BIN", "ffmpeg"),
	}
}

func NewApp(cfg Config) *App {
	app := &App{
		cfg:        cfg,
		client:     &http.Client{Timeout: 90 * time.Second},
		start:      time.Now(),
		owner:      fmt.Sprintf("go-bot-%d-%s", os.Getpid(), randomToken(6)),
		metrics:    map[string]int64{"tts": 0, "ocr": 0, "voice": 0, "audio": 0, "blocked_hits": 0, "disabled_hits": 0, "errors": 0},
		apiCache:   make(map[string]apiCacheEntry),
		memoryKeys: make(map[string]APIKeyRow),
		settings:   copyMap(botSettingDefaults),
		blocked:    make(map[int64]bool),
		blockedTS:  make(map[int64]time.Time),
	}
	if cfg.RedisURL != "" {
		r, err := NewMiniRedis(cfg.RedisURL)
		if err != nil {
			log.Printf("Redis disabled: %v", err)
		} else {
			app.redis = r
		}
	}
	return app
}

func (a *App) registerRoutes(mux *http.ServeMux) {
	mux.HandleFunc("/", a.health)
	mux.HandleFunc("/ping", a.ping)
	mux.HandleFunc("/ai-assistant", a.aiAssistant)
	mux.HandleFunc("/ai-assistant/vision", a.aiVision)
	mux.HandleFunc("/ai-assistant/transcribe", a.aiTranscribe)
	mux.HandleFunc("/ai-assistant/info", a.aiInfo)
	mux.HandleFunc("/telegram/webhook", a.telegramWebhook)

	mux.HandleFunc("/admin/login", a.webLogin)
	mux.HandleFunc("/admin/logout", a.webLogout)
	mux.HandleFunc("/admin/status.json", a.adminRequired(a.webStatusJSON))
	mux.HandleFunc("/admin/live.json", a.adminRequired(a.webLiveJSON))
	mux.HandleFunc("/admin/users/action", a.adminRequired(a.webUsersAction))
	mux.HandleFunc("/admin/users/", a.adminRequired(a.webUserDetail))
	mux.HandleFunc("/admin/users", a.adminRequired(a.webUsers))
	mux.HandleFunc("/admin/schedules/action", a.adminRequired(a.webSchedulesAction))
	mux.HandleFunc("/admin/schedules", a.adminRequired(a.webSchedules))
	mux.HandleFunc("/admin/broadcast", a.adminRequired(a.webBroadcast))
	mux.HandleFunc("/admin/settings", a.adminRequired(a.webSettings))
	mux.HandleFunc("/admin/api-keys", a.adminRequired(a.webAPIKeys))
	mux.HandleFunc("/admin/locks", a.adminRequired(a.webLocks))
	mux.HandleFunc("/admin/sql", a.adminRequired(a.webSQL))
	mux.HandleFunc("/admin/health", a.adminRequired(a.webHealth))
	mux.HandleFunc("/admin", a.adminRequired(a.webHome))
	mux.HandleFunc("/dashboard", func(w http.ResponseWriter, r *http.Request) { http.Redirect(w, r, "/admin", http.StatusFound) })
}

func (a *App) securityMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("Referrer-Policy", "strict-origin-when-cross-origin")
		w.Header().Set("Permissions-Policy", "camera=(), microphone=(), geolocation=()")
		next.ServeHTTP(w, r)
	})
}

func (a *App) health(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path != "/" {
		http.NotFound(w, r)
		return
	}
	w.Header().Set("Content-Type", "text/plain; charset=utf-8")
	_, _ = w.Write([]byte("Bot is running!"))
}
func (a *App) ping(w http.ResponseWriter, r *http.Request) { _, _ = w.Write([]byte("pong")) }

func (a *App) keepAliveLoop() {
	time.Sleep(10 * time.Second)
	for {
		urls := []string{a.cfg.RenderExternalURL}
		if !strings.HasSuffix(a.cfg.RenderExternalURL, "/ping") {
			urls = append(urls, a.cfg.RenderExternalURL+"/ping")
		}
		ok := false
		for _, u := range urls {
			req, _ := http.NewRequest("GET", u, nil)
			req.Header.Set("User-Agent", "GoBot-KeepAlive/1.0")
			resp, err := a.client.Do(req)
			if err == nil && resp.Body != nil {
				io.Copy(io.Discard, resp.Body)
				resp.Body.Close()
			}
			if err == nil && resp.StatusCode >= 200 && resp.StatusCode < 400 {
				ok = true
				log.Printf("Keep-alive OK -> %d %s", resp.StatusCode, u)
				break
			}
			if err != nil {
				log.Printf("Keep-alive failed for %s: %v", u, err)
			} else {
				log.Printf("Keep-alive non-OK -> %d %s", resp.StatusCode, u)
			}
		}
		if !ok {
			log.Printf("Keep-alive failed for all URLs. Check RENDER_EXTERNAL_URL.")
		}
		time.Sleep(240 * time.Second)
	}
}

// ---------------- HTTP AI API ----------------
func (a *App) aiAssistant(w http.ResponseWriter, r *http.Request) {
	if handleCORS(w, r) {
		return
	}
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}
	if !a.checkAIAPIKey(r) {
		writeAIError(w, "Unauthorized — invalid or missing API key.", 401)
		return
	}
	req, err := parseAIRequest(r)
	if err != nil {
		writeAIError(w, err.Error(), 400)
		return
	}
	if req.Stream {
		writeAIError(w, "Streaming is disabled. Send stream=false.", 400)
		return
	}
	if req.Message == "" && len(req.ImageData) == 0 && len(req.AudioData) == 0 {
		writeAIError(w, "Provide at least one of: message, image, or audio.", 400)
		return
	}
	if len(req.Message) > maxMessageChars {
		writeAIError(w, "Message too long.", 400)
		return
	}

	if len(req.ImageData) > 0 {
		if !allowedImageMIME[req.ImageMIME] {
			writeAIError(w, "Unsupported image type: "+req.ImageMIME, 400)
			return
		}
		ocr, provider, model, err := a.askOCRImage(req.ImageData, req.ImageMIME)
		if err != nil {
			writeAIError(w, "Vision OCR failed: "+err.Error(), 500)
			return
		}
		reply := ocr
		modelUsed := model
		var tokens any
		if strings.TrimSpace(req.Message) != "" {
			prompt := "User instruction: " + req.Message + "\n\nOCR text extracted from image:\n" + ocr + "\n\nAnswer using the OCR text above."
			reply, modelUsed, tokens, err = a.aiTextReply(prompt, req.History)
			if err != nil {
				writeAIError(w, "AI generation failed: "+err.Error(), 500)
				return
			}
		}
		writeJSON(w, 200, map[string]any{"ok": true, "reply": reply, "ocr_text": ocr, "detected_language": detectLang(reply + ocr), "tokens_used": tokens, "model": modelUsed, "ocr_model": model, "ocr_provider": provider, "provider": a.cfg.AIProvider})
		return
	}
	if len(req.AudioData) > 0 {
		if !allowedAudioMIME[req.AudioMIME] {
			writeAIError(w, "Unsupported audio type: "+req.AudioMIME, 400)
			return
		}
		if a.cfg.GeminiAPIKey == "" {
			writeAIError(w, "Audio transcription requires GEMINI_API_KEY and GEMINI_MODEL.", 503)
			return
		}
		reply, err := a.geminiGenerate(req.Message, req.History, nil, "", req.AudioData, req.AudioMIME, "Transcribe this audio exactly as spoken, then answer the user if they gave an instruction.")
		if err != nil {
			writeAIError(w, "Transcription failed: "+err.Error(), 500)
			return
		}
		writeJSON(w, 200, map[string]any{"ok": true, "reply": reply, "detected_language": detectLang(reply), "tokens_used": nil, "model": a.cfg.GeminiModel, "provider": "gemini"})
		return
	}
	reply, model, tokens, err := a.aiTextReply(req.Message, req.History)
	if err != nil {
		writeAIError(w, "AI generation failed: "+err.Error(), 500)
		return
	}
	writeJSON(w, 200, map[string]any{"ok": true, "reply": reply, "detected_language": detectLang(reply + req.Message), "tokens_used": tokens, "model": model, "provider": "hf"})
}

func (a *App) aiVision(w http.ResponseWriter, r *http.Request) {
	if handleCORS(w, r) {
		return
	}
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}
	if !a.checkAIAPIKey(r) {
		writeAIError(w, "Unauthorized.", 401)
		return
	}
	req, err := parseAIRequest(r)
	if err != nil {
		writeAIError(w, err.Error(), 400)
		return
	}
	if len(req.ImageData) == 0 {
		writeAIError(w, "No image provided.", 400)
		return
	}
	ocr, provider, model, err := a.askOCRImage(req.ImageData, req.ImageMIME)
	if err != nil {
		writeAIError(w, "Vision OCR failed: "+err.Error(), 500)
		return
	}
	a.metricInc("ocr", 1)
	writeJSON(w, 200, map[string]any{"ok": true, "result": ocr, "detected_language": detectLang(ocr), "model": model, "provider": provider, "ocr_provider": provider})
}

func (a *App) aiTranscribe(w http.ResponseWriter, r *http.Request) {
	if handleCORS(w, r) {
		return
	}
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}
	if !a.checkAIAPIKey(r) {
		writeAIError(w, "Unauthorized.", 401)
		return
	}
	req, err := parseAIRequest(r)
	if err != nil {
		writeAIError(w, err.Error(), 400)
		return
	}
	if len(req.AudioData) == 0 {
		writeAIError(w, "No audio file provided.", 400)
		return
	}
	if a.cfg.GeminiAPIKey == "" {
		writeAIError(w, "AI service not configured.", 503)
		return
	}
	langHint := r.FormValue("language")
	inst := "Transcribe this audio exactly as spoken. Output only the transcribed text."
	if langHint == "km" {
		inst += " The audio is in Khmer."
	}
	if langHint == "en" {
		inst += " The audio is in English."
	}
	transcript, err := a.geminiGenerate("", nil, nil, "", req.AudioData, req.AudioMIME, inst)
	if err != nil {
		writeAIError(w, "Transcription failed: "+err.Error(), 500)
		return
	}
	a.metricInc("audio", 1)
	writeJSON(w, 200, map[string]any{"ok": true, "transcript": transcript, "detected_language": detectLang(transcript), "model": a.cfg.GeminiModel})
}

func (a *App) aiInfo(w http.ResponseWriter, r *http.Request) {
	writeJSON(w, 200, map[string]any{
		"ok": true, "provider": a.cfg.AIProvider, "model": a.cfg.HFModel, "ocr_model": a.cfg.HFOCRModel, "ocr_provider": a.cfg.OCRProvider,
		"features":              []string{"chat", "multi-turn-history", "image-ocr", "khmer-language", "english-language", "admin-generated-api-keys", "telegram-long-polling", "scheduled-broadcasts"},
		"providers":             map[string]any{"active": a.cfg.AIProvider, "huggingface_available": a.cfg.HFToken != "", "huggingface_model": a.cfg.HFModel, "huggingface_ocr_model": a.cfg.HFOCRModel, "gemini_available": a.cfg.GeminiAPIKey != "", "gemini_model": a.cfg.GeminiModel},
		"limits":                map[string]int{"max_message_chars": maxMessageChars, "max_image_bytes": maxImageBytes, "max_audio_bytes": maxAudioBytes, "max_history_turns": maxHistoryTurns},
		"supported_image_types": keysBool(allowedImageMIME), "supported_audio_types": keysBool(allowedAudioMIME), "auth_required": true,
		"auth_configured": a.cfg.HFToken != "" || a.cfg.GeminiAPIKey != "" || a.hasDynamicAuth(),
	})
}

func handleCORS(w http.ResponseWriter, r *http.Request) bool {
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.Header().Set("Access-Control-Allow-Methods", "POST, OPTIONS")
	w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization, X-Api-Key")
	if r.Method == http.MethodOptions {
		w.WriteHeader(204)
		return true
	}
	return false
}

func writeAIError(w http.ResponseWriter, msg string, code int) {
	writeJSON(w, code, map[string]any{"ok": false, "error": msg, "code": code})
}

func parseAIRequest(r *http.Request) (ParsedAIRequest, error) {
	ct := r.Header.Get("Content-Type")
	var out ParsedAIRequest
	if strings.Contains(ct, "application/json") {
		var body AIJSONRequest
		if err := json.NewDecoder(io.LimitReader(r.Body, maxAudioBytes+maxImageBytes+maxMessageChars+4096)).Decode(&body); err != nil {
			return out, errors.New("Invalid JSON body")
		}
		out.Message = strings.TrimSpace(body.Message)
		out.Stream = body.Stream
		out.History = body.History
		if body.ImageBase64 != "" {
			mime := body.ImageMIME
			if mime == "" {
				mime = "image/jpeg"
			}
			if !allowedImageMIME[mime] {
				return out, fmt.Errorf("Unsupported image type: %s", mime)
			}
			data, err := base64.StdEncoding.DecodeString(body.ImageBase64)
			if err != nil {
				return out, errors.New("Invalid base64 image data")
			}
			if len(data) > maxImageBytes {
				return out, errors.New("Image too large (max 10 MB)")
			}
			out.ImageData, out.ImageMIME = data, mime
		}
		if body.AudioBase64 != "" {
			mime := body.AudioMIME
			if mime == "" {
				mime = "audio/mpeg"
			}
			if !allowedAudioMIME[mime] {
				return out, fmt.Errorf("Unsupported audio type: %s", mime)
			}
			data, err := base64.StdEncoding.DecodeString(body.AudioBase64)
			if err != nil {
				return out, errors.New("Invalid base64 audio data")
			}
			if len(data) > maxAudioBytes {
				return out, errors.New("Audio too large (max 50 MB)")
			}
			out.AudioData, out.AudioMIME = data, mime
		}
		return out, nil
	}
	if strings.Contains(ct, "multipart/form-data") || strings.Contains(ct, "application/x-www-form-urlencoded") {
		if err := r.ParseMultipartForm(maxAudioBytes + maxImageBytes + 1<<20); err != nil && !strings.Contains(ct, "application/x-www-form-urlencoded") {
			return out, errors.New("Invalid multipart form")
		}
		out.Message = strings.TrimSpace(r.FormValue("message"))
		out.Stream = strings.ToLower(r.FormValue("stream")) == "true"
		if raw := r.FormValue("history"); raw != "" {
			_ = json.Unmarshal([]byte(raw), &out.History)
		}
		if r.MultipartForm != nil {
			if data, mime, ok, err := readMultipartFile(r.MultipartForm, "image", maxImageBytes, "image/jpeg"); err != nil {
				return out, err
			} else if ok {
				if !allowedImageMIME[mime] {
					return out, fmt.Errorf("Unsupported image type: %s", mime)
				}
				out.ImageData, out.ImageMIME = data, mime
			}
			if data, mime, ok, err := readMultipartFile(r.MultipartForm, "audio", maxAudioBytes, "audio/mpeg"); err != nil {
				return out, err
			} else if ok {
				if !allowedAudioMIME[mime] {
					return out, fmt.Errorf("Unsupported audio type: %s", mime)
				}
				out.AudioData, out.AudioMIME = data, mime
			}
		}
		return out, nil
	}
	return out, errors.New("Content-Type must be multipart/form-data or application/json")
}

func readMultipartFile(form *multipart.Form, name string, max int64, defaultMIME string) ([]byte, string, bool, error) {
	files := form.File[name]
	if len(files) == 0 {
		return nil, "", false, nil
	}
	fh := files[0]
	f, err := fh.Open()
	if err != nil {
		return nil, "", false, err
	}
	defer f.Close()
	data, err := io.ReadAll(io.LimitReader(f, max+1))
	if err != nil {
		return nil, "", false, err
	}
	if int64(len(data)) > max {
		return nil, "", false, fmt.Errorf("%s file too large", name)
	}
	mime := fh.Header.Get("Content-Type")
	if mime == "" {
		mime = defaultMIME
	}
	return data, mime, true, nil
}

// ---------------- AI providers ----------------
func (a *App) aiTextReply(message string, history []HistoryTurn) (string, string, any, error) {
	if a.cfg.AIProvider == "gemini" && a.cfg.GeminiAPIKey != "" {
		txt, err := a.geminiGenerate(message, history, nil, "", nil, "", aiSystemPrompt)
		return txt, a.cfg.GeminiModel, nil, err
	}
	if a.cfg.HFToken == "" {
		return "", a.cfg.HFModel, nil, errors.New("Hugging Face is not configured. Set HF_TOKEN")
	}
	prompt := buildHFPrompt(message, history)
	endpoint := "https://api-inference.huggingface.co/models/" + url.PathEscape(a.cfg.HFModel)
	payload := map[string]any{"inputs": prompt, "parameters": map[string]any{"max_new_tokens": 2048, "temperature": 0.7, "return_full_text": false}}
	var raw any
	if err := a.hfPostJSON(endpoint, payload, &raw); err != nil {
		return "", a.cfg.HFModel, nil, err
	}
	text := strings.TrimSpace(extractGeneratedText(raw))
	if text == "" {
		text = strings.TrimSpace(fmt.Sprint(raw))
	}
	return text, a.cfg.HFModel, nil, nil
}

func buildHFPrompt(message string, history []HistoryTurn) string {
	var b strings.Builder
	b.WriteString("System: " + aiSystemPrompt + "\n\n")
	start := 0
	if len(history) > maxHistoryTurns {
		start = len(history) - maxHistoryTurns
	}
	for _, h := range history[start:] {
		role := strings.TrimSpace(h.Role)
		if role == "" {
			role = "user"
		}
		b.WriteString(strings.Title(role) + ": " + strings.TrimSpace(h.Content) + "\n")
	}
	b.WriteString("User: " + message + "\nAssistant:")
	return b.String()
}

func (a *App) hfPostJSON(endpoint string, payload any, out any) error {
	data, _ := json.Marshal(payload)
	req, err := http.NewRequest("POST", endpoint, bytes.NewReader(data))
	if err != nil {
		return err
	}
	req.Header.Set("Authorization", "Bearer "+a.cfg.HFToken)
	req.Header.Set("Content-Type", "application/json")
	resp, err := a.client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()
	body, _ := io.ReadAll(io.LimitReader(resp.Body, 8<<20))
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fmt.Errorf("HF HTTP %d: %s", resp.StatusCode, strings.TrimSpace(string(body)))
	}
	return json.Unmarshal(body, out)
}

func (a *App) askOCRImage(data []byte, mime string) (string, string, string, error) {
	provider := a.cfg.OCRProvider
	if provider == "" || provider == "auto" {
		provider = "hf"
	}
	if provider == "gemini" && a.cfg.GeminiAPIKey != "" {
		text, err := a.geminiGenerate("Extract all readable text from this image. Return only the text.", nil, data, mime, nil, "", aiSystemPrompt)
		return text, "gemini", a.cfg.GeminiModel, err
	}
	if a.cfg.HFToken == "" {
		return "", "hf", a.cfg.HFOCRModel, errors.New("HF_TOKEN is missing")
	}
	endpoint := "https://api-inference.huggingface.co/models/" + url.PathEscape(a.cfg.HFOCRModel)
	req, err := http.NewRequest("POST", endpoint, bytes.NewReader(data))
	if err != nil {
		return "", "hf", a.cfg.HFOCRModel, err
	}
	req.Header.Set("Authorization", "Bearer "+a.cfg.HFToken)
	req.Header.Set("Content-Type", mime)
	resp, err := a.client.Do(req)
	if err != nil {
		return "", "hf", a.cfg.HFOCRModel, err
	}
	defer resp.Body.Close()
	body, _ := io.ReadAll(io.LimitReader(resp.Body, 8<<20))
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return "", "hf", a.cfg.HFOCRModel, fmt.Errorf("HF OCR HTTP %d: %s", resp.StatusCode, strings.TrimSpace(string(body)))
	}
	var raw any
	if err := json.Unmarshal(body, &raw); err != nil {
		return strings.TrimSpace(string(body)), "hf", a.cfg.HFOCRModel, nil
	}
	text := strings.TrimSpace(extractGeneratedText(raw))
	if text == "" {
		text = strings.TrimSpace(fmt.Sprint(raw))
	}
	return text, "hf", a.cfg.HFOCRModel, nil
}

func (a *App) geminiGenerate(message string, history []HistoryTurn, image []byte, imageMIME string, audio []byte, audioMIME string, instruction string) (string, error) {
	if a.cfg.GeminiAPIKey == "" {
		return "", errors.New("GEMINI_API_KEY is missing")
	}
	parts := []map[string]any{}
	if len(image) > 0 {
		parts = append(parts, map[string]any{"inline_data": map[string]any{"mime_type": imageMIME, "data": base64.StdEncoding.EncodeToString(image)}})
	}
	if len(audio) > 0 {
		parts = append(parts, map[string]any{"inline_data": map[string]any{"mime_type": audioMIME, "data": base64.StdEncoding.EncodeToString(audio)}})
	}
	if message != "" {
		parts = append(parts, map[string]any{"text": message})
	}
	if len(parts) == 0 {
		parts = append(parts, map[string]any{"text": "Hello"})
	}
	contents := []map[string]any{}
	start := 0
	if len(history) > maxHistoryTurns {
		start = len(history) - maxHistoryTurns
	}
	for _, h := range history[start:] {
		role := "user"
		if h.Role == "assistant" || h.Role == "model" {
			role = "model"
		}
		contents = append(contents, map[string]any{"role": role, "parts": []map[string]any{{"text": h.Content}}})
	}
	contents = append(contents, map[string]any{"role": "user", "parts": parts})
	if instruction == "" {
		instruction = aiSystemPrompt
	}
	payload := map[string]any{
		"system_instruction": map[string]any{"parts": []map[string]any{{"text": instruction}}},
		"contents":           contents,
		"generationConfig":   map[string]any{"temperature": 0.7, "maxOutputTokens": 8192},
	}
	endpoint := fmt.Sprintf("https://generativelanguage.googleapis.com/v1beta/models/%s:generateContent?key=%s", url.PathEscape(a.cfg.GeminiModel), url.QueryEscape(a.cfg.GeminiAPIKey))
	data, _ := json.Marshal(payload)
	req, _ := http.NewRequest("POST", endpoint, bytes.NewReader(data))
	req.Header.Set("Content-Type", "application/json")
	resp, err := a.client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()
	body, _ := io.ReadAll(io.LimitReader(resp.Body, 16<<20))
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return "", fmt.Errorf("Gemini HTTP %d: %s", resp.StatusCode, strings.TrimSpace(string(body)))
	}
	var raw map[string]any
	if err := json.Unmarshal(body, &raw); err != nil {
		return "", err
	}
	text := extractGeminiText(raw)
	if strings.TrimSpace(text) == "" {
		return "", errors.New("Gemini returned empty text")
	}
	return strings.TrimSpace(text), nil
}

func extractGeneratedText(v any) string {
	switch x := v.(type) {
	case []any:
		for _, item := range x {
			if s := extractGeneratedText(item); s != "" {
				return s
			}
		}
	case map[string]any:
		for _, k := range []string{"generated_text", "text", "summary_text", "translation_text", "answer"} {
			if val, ok := x[k]; ok {
				if s, ok := val.(string); ok && strings.TrimSpace(s) != "" {
					return s
				}
			}
		}
		for _, val := range x {
			if s := extractGeneratedText(val); s != "" {
				return s
			}
		}
	case string:
		return x
	}
	return ""
}

func extractGeminiText(raw map[string]any) string {
	cands, _ := raw["candidates"].([]any)
	var out strings.Builder
	for _, c := range cands {
		cm, _ := c.(map[string]any)
		content, _ := cm["content"].(map[string]any)
		parts, _ := content["parts"].([]any)
		for _, p := range parts {
			pm, _ := p.(map[string]any)
			if s, ok := pm["text"].(string); ok {
				out.WriteString(s)
			}
		}
	}
	return out.String()
}

// ---------------- API key authentication ----------------
func (a *App) extractAIRequestKey(r *http.Request) string {
	auth := strings.TrimSpace(r.Header.Get("Authorization"))
	bearer := ""
	if strings.HasPrefix(strings.ToLower(auth), "bearer ") {
		bearer = strings.TrimSpace(auth[7:])
	}
	if k := strings.TrimSpace(r.Header.Get("X-Api-Key")); k != "" {
		return k
	}
	if bearer != "" {
		return bearer
	}
	return strings.TrimSpace(r.URL.Query().Get("api_key"))
}
func hashAIKey(raw string) string {
	sum := sha256.Sum256([]byte(raw))
	return hex.EncodeToString(sum[:])
}
func (a *App) checkAIAPIKey(r *http.Request) bool {
	key := a.extractAIRequestKey(r)
	if key == "" {
		return false
	}
	if static := envStr("AI_API_KEY", ""); static != "" && hmac.Equal([]byte(key), []byte(static)) {
		return true
	}
	return a.validateDynamicAIAPIKey(key)
}
func (a *App) validateDynamicAIAPIKey(raw string) bool {
	raw = strings.TrimSpace(raw)
	if raw == "" || len(raw) > 256 || !strings.HasPrefix(raw, apiKeyPrefix) {
		return false
	}
	kh := hashAIKey(raw)
	now := time.Now()
	a.mu.RLock()
	c, ok := a.apiCache[kh]
	a.mu.RUnlock()
	if ok && now.Before(c.Exp) {
		if c.Valid {
			go a.touchAPIKey(c.RowID)
		}
		return c.Valid
	}
	a.mu.RLock()
	mem, ok := a.memoryKeys[kh]
	a.mu.RUnlock()
	if ok {
		valid := mem.Active && mem.RevokedAt == nil
		a.setAPICache(kh, valid, mem.ID)
		return valid
	}
	if a.cfg.SupabaseURL == "" || a.cfg.SupabaseKey == "" {
		a.setAPICache(kh, false, 0)
		return false
	}
	var rows []APIKeyRow
	q := url.Values{"select": {"id,active,revoked_at"}, "key_hash": {"eq." + kh}, "limit": {"1"}}
	if err := a.supabaseGet("ai_api_keys", q, &rows); err != nil {
		log.Printf("Dynamic AI API key validation unavailable: %v", err)
		a.setAPICache(kh, false, 0)
		return false
	}
	valid := len(rows) > 0 && rows[0].Active && rows[0].RevokedAt == nil
	rowID := int64(0)
	if len(rows) > 0 {
		rowID = rows[0].ID
	}
	a.setAPICache(kh, valid, rowID)
	if valid {
		go a.touchAPIKey(rowID)
	}
	return valid
}
func (a *App) setAPICache(hash string, valid bool, rowID int64) {
	a.mu.Lock()
	a.apiCache[hash] = apiCacheEntry{valid, rowID, time.Now().Add(60 * time.Second)}
	a.mu.Unlock()
}
func (a *App) touchAPIKey(rowID int64) {
	if rowID == 0 {
		return
	}
	patch := map[string]any{"last_used_at": time.Now().UTC().Format(time.RFC3339Nano)}
	_ = a.supabasePatch("ai_api_keys", url.Values{"id": {"eq." + strconv.FormatInt(rowID, 10)}}, patch, nil)
}
func (a *App) hasDynamicAuth() bool {
	a.mu.RLock()
	if len(a.memoryKeys) > 0 {
		a.mu.RUnlock()
		return true
	}
	a.mu.RUnlock()
	var rows []APIKeyRow
	err := a.supabaseGet("ai_api_keys", url.Values{"select": {"id"}, "active": {"eq.true"}, "limit": {"1"}}, &rows)
	return err == nil && len(rows) > 0
}
func generateAPIKey() string { return apiKeyPrefix + randomToken(apiKeyRandomBytes) }
func (a *App) createAPIKey(adminID int64, note string) (string, APIKeyRow, string, error) {
	raw := generateAPIKey()
	kh := hashAIKey(raw)
	prefix := raw
	if len(prefix) > apiKeyDisplayChars {
		prefix = prefix[:apiKeyDisplayChars]
	}
	note = strings.TrimSpace(note)
	if len(note) > 120 {
		note = note[:120]
	}
	var notePtr *string
	if note != "" {
		notePtr = &note
	}
	row := APIKeyRow{KeyPrefix: prefix, KeyHash: kh, AdminID: adminID, Note: notePtr, Active: true, CreatedAt: time.Now().UTC().Format(time.RFC3339Nano)}
	if a.cfg.SupabaseURL == "" || a.cfg.SupabaseKey == "" {
		row.ID = time.Now().UnixMilli()
		a.mu.Lock()
		a.memoryKeys[kh] = row
		a.apiCache = make(map[string]apiCacheEntry)
		a.mu.Unlock()
		return raw, row, "memory", nil
	}
	var rows []APIKeyRow
	if err := a.supabaseInsert("ai_api_keys", row, &rows); err != nil {
		return "", row, "", err
	}
	if len(rows) > 0 {
		row = rows[0]
	}
	a.mu.Lock()
	a.apiCache = make(map[string]apiCacheEntry)
	a.mu.Unlock()
	return raw, row, "supabase", nil
}
func (a *App) listAPIKeys(limit int) []APIKeyRow {
	if limit < 1 || limit > 50 {
		limit = 20
	}
	if a.cfg.SupabaseURL == "" || a.cfg.SupabaseKey == "" {
		a.mu.RLock()
		rows := make([]APIKeyRow, 0, len(a.memoryKeys))
		for _, r := range a.memoryKeys {
			rows = append(rows, r)
		}
		a.mu.RUnlock()
		sort.Slice(rows, func(i, j int) bool { return rows[i].CreatedAt > rows[j].CreatedAt })
		if len(rows) > limit {
			rows = rows[:limit]
		}
		return rows
	}
	var rows []APIKeyRow
	_ = a.supabaseGet("ai_api_keys", url.Values{"select": {"id,key_prefix,admin_id,note,active,created_at,revoked_at,last_used_at"}, "order": {"created_at.desc"}, "limit": {strconv.Itoa(limit)}}, &rows)
	return rows
}
func (a *App) revokeAPIKey(ident string) (bool, string) {
	ident = strings.TrimSpace(ident)
	if ident == "" {
		return false, "Missing key id or prefix."
	}
	now := time.Now().UTC().Format(time.RFC3339Nano)
	if a.cfg.SupabaseURL == "" || a.cfg.SupabaseKey == "" {
		a.mu.Lock()
		defer a.mu.Unlock()
		for kh, row := range a.memoryKeys {
			if strconv.FormatInt(row.ID, 10) == ident || row.KeyPrefix == ident {
				row.Active = false
				row.RevokedAt = &now
				a.memoryKeys[kh] = row
				a.apiCache = make(map[string]apiCacheEntry)
				return true, row.KeyPrefix
			}
		}
		return false, "API key not found."
	}
	filt := url.Values{}
	if _, err := strconv.ParseInt(ident, 10, 64); err == nil {
		filt.Set("id", "eq."+ident)
	} else {
		filt.Set("key_prefix", "eq."+ident)
	}
	var rows []APIKeyRow
	if err := a.supabasePatch("ai_api_keys", filt, map[string]any{"active": false, "revoked_at": now}, &rows); err != nil || len(rows) == 0 {
		return false, "API key not found."
	}
	a.mu.Lock()
	a.apiCache = make(map[string]apiCacheEntry)
	a.mu.Unlock()
	return true, rows[0].KeyPrefix
}

// ---------------- Supabase REST ----------------
func (a *App) supabaseRequest(method, table string, q url.Values, body any, out any, prefer string) error {
	if a.cfg.SupabaseURL == "" || a.cfg.SupabaseKey == "" {
		return errors.New("Supabase not configured")
	}
	u := a.cfg.SupabaseURL + "/rest/v1/" + url.PathEscape(table)
	if len(q) > 0 {
		u += "?" + q.Encode()
	}
	var rdr io.Reader
	if body != nil {
		b, _ := json.Marshal(body)
		rdr = bytes.NewReader(b)
	}
	req, err := http.NewRequest(method, u, rdr)
	if err != nil {
		return err
	}
	req.Header.Set("apikey", a.cfg.SupabaseKey)
	req.Header.Set("Authorization", "Bearer "+a.cfg.SupabaseKey)
	req.Header.Set("Content-Type", "application/json")
	if prefer != "" {
		req.Header.Set("Prefer", prefer)
	}
	resp, err := a.client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()
	data, _ := io.ReadAll(io.LimitReader(resp.Body, 16<<20))
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fmt.Errorf("supabase %s %s HTTP %d: %s", method, table, resp.StatusCode, strings.TrimSpace(string(data)))
	}
	if out != nil && len(data) > 0 {
		return json.Unmarshal(data, out)
	}
	return nil
}
func (a *App) supabaseGet(table string, q url.Values, out any) error {
	return a.supabaseRequest("GET", table, q, nil, out, "")
}
func (a *App) supabaseInsert(table string, body any, out any) error {
	return a.supabaseRequest("POST", table, nil, body, out, "return=representation")
}
func (a *App) supabaseUpsert(table string, body any, onConflict string, out any) error {
	q := url.Values{}
	if onConflict != "" {
		q.Set("on_conflict", onConflict)
	}
	return a.supabaseRequest("POST", table, q, body, out, "resolution=merge-duplicates,return=representation")
}
func (a *App) supabasePatch(table string, q url.Values, body any, out any) error {
	return a.supabaseRequest("PATCH", table, q, body, out, "return=representation")
}
func (a *App) supabaseDelete(table string, q url.Values, out any) error {
	return a.supabaseRequest("DELETE", table, q, nil, out, "return=representation")
}

// ---------------- Web Admin ----------------
type SessionClaims struct {
	AdminID int64  `json:"admin_id"`
	CSRF    string `json:"csrf"`
	Exp     int64  `json:"exp"`
}

func (a *App) adminRequired(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if !a.cfg.WebAdminEnabled {
			http.Error(w, "WEB_ADMIN_ENABLED=0", 403)
			return
		}
		if a.cfg.WebAdminPassword == "" {
			a.render(w, r, "Setup required", "<div class='card'>Set ADMIN_WEB_PASSWORD or WEB_ADMIN_PASSWORD.</div>", "dashboard", 503)
			return
		}
		s, ok := a.readSession(r)
		if !ok {
			http.Redirect(w, r, "/admin/login?next="+url.QueryEscape(r.URL.RequestURI()), http.StatusFound)
			return
		}
		_ = s
		next(w, r)
	}
}
func (a *App) webLogin(w http.ResponseWriter, r *http.Request) {
	if r.Method == http.MethodPost {
		_ = r.ParseForm()
		pass := r.FormValue("password")
		adminID := parseInt64(r.FormValue("admin_id"), a.defaultAdminID())
		if pass == a.cfg.WebAdminPassword && a.validAdminID(adminID) {
			claims := SessionClaims{AdminID: adminID, CSRF: randomToken(24), Exp: time.Now().Add(14 * 24 * time.Hour).Unix()}
			a.setSession(w, claims)
			next := r.FormValue("next")
			if next == "" || !strings.HasPrefix(next, "/") || strings.HasPrefix(next, "//") {
				next = "/admin"
			}
			http.Redirect(w, r, next, http.StatusFound)
			return
		}
		a.render(w, r, "Login", loginHTML(true, r.URL.Query().Get("next"), a.cfg.AdminIDList), "login", 401)
		return
	}
	a.render(w, r, "Login", loginHTML(false, r.URL.Query().Get("next"), a.cfg.AdminIDList), "login", 200)
}
func loginHTML(bad bool, next string, ids []int64) string {
	idVal := int64(0)
	if len(ids) > 0 {
		idVal = ids[0]
	}
	msg := ""
	if bad {
		msg = "<div class='flash error'>Invalid password or admin ID.</div>"
	}
	return fmt.Sprintf(`<div class="card" style="max-width:520px"><h2>Admin Login</h2>%s<form method="post"><input type="hidden" name="next" value="%s"><div class="field"><label>Admin ID</label><input name="admin_id" value="%d"></div><div class="field"><label>Password</label><input name="password" type="password" autofocus></div><button>Login</button></form></div>`, msg, html.EscapeString(next), idVal)
}
func (a *App) webLogout(w http.ResponseWriter, r *http.Request) {
	http.SetCookie(w, &http.Cookie{Name: a.cfg.WebSessionCookie, Value: "", Path: "/", MaxAge: -1})
	http.Redirect(w, r, "/admin/login", http.StatusFound)
}
