func (a *App) webUsersAction(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", 405)
		return
	}
	if !a.checkCSRF(r) {
		http.Error(w, "bad csrf", 403)
		return
	}
	_ = r.ParseForm()
	userID := parseInt64(r.FormValue("user_id"), 0)
	action := r.FormValue("action")
	switch action {
	case "block":
		a.setBlocked(userID, a.currentAdminID(r), true, "blocked from web admin")
	case "unblock":
		a.setBlocked(userID, a.currentAdminID(r), false, "")
	case "clear_history":
		_ = a.supabaseDelete("text_cache", url.Values{"user_id": {"eq." + strconv.FormatInt(userID, 10)}}, nil)
		_ = a.supabaseDelete("conversation_history", url.Values{"user_id": {"eq." + strconv.FormatInt(userID, 10)}}, nil)
	case "send_message":
		_ = a.telegramSendMessage(userID, r.FormValue("message"), "")
	}
	http.Redirect(w, r, "/admin/users/"+strconv.FormatInt(userID, 10), http.StatusFound)
}
