func (a *App) webBroadcast(w http.ResponseWriter, r *http.Request) {
	csrf := a.csrf(r)
	if r.Method == http.MethodPost {
		if !a.checkCSRF(r) {
			http.Error(w, "bad csrf", 403)
			return
		}
		_ = r.ParseForm()
		text := strings.TrimSpace(r.FormValue("text"))
		when := strings.TrimSpace(r.FormValue("broadcast_at"))
		mode := r.FormValue("mode")
		if text == "" {
			http.Redirect(w, r, "/admin/broadcast", http.StatusFound)
			return
		}
		if mode == "schedule" && when != "" {
			dt, err := a.parseLocalSchedule(when)
			if err == nil {
				_, _ = a.insertSchedule(a.currentAdminID(r), nil, nil, &text, dt, true)
			}
		} else {
			go a.broadcastTextToAll(text)
		}
		http.Redirect(w, r, "/admin/broadcast", http.StatusFound)
		return
	}
	body := fmt.Sprintf(`<div class="card"><h2>Broadcast</h2><form method="post"><input type="hidden" name="csrf_token" value="%s"><div class="field"><label>Message</label><textarea name="text" required></textarea></div><div class="row"><div class="field"><label>Mode</label><select name="mode"><option value="now">Send now</option><option value="schedule">Schedule preview</option></select></div><div class="field"><label>Broadcast time (%s)</label><input type="datetime-local" name="broadcast_at"></div></div><button>Submit</button></form></div>`, csrf, html.EscapeString(a.timeHint()))
	a.render(w, r, "Broadcast", body, "broadcast", 200)
}
