// ---------------- Web helpers/session ----------------
func (a *App) defaultAdminID() int64 {
	if len(a.cfg.AdminIDList) > 0 {
		return a.cfg.AdminIDList[0]
	}
	return 0
}
func (a *App) validAdminID(id int64) bool {
	if len(a.cfg.AdminIDs) == 0 {
		return true
	}
	return a.cfg.AdminIDs[id]
}
func (a *App) signBytes(data []byte) string {
	mac := hmac.New(sha256.New, []byte(a.cfg.WebSecret))
	mac.Write(data)
	return hex.EncodeToString(mac.Sum(nil))
}
func (a *App) setSession(w http.ResponseWriter, s SessionClaims) {
	b, _ := json.Marshal(s)
	val := base64.RawURLEncoding.EncodeToString(b) + "." + a.signBytes(b)
	http.SetCookie(w, &http.Cookie{Name: a.cfg.WebSessionCookie, Value: val, Path: "/", HttpOnly: true, Secure: a.cfg.WebCookieSecure, SameSite: http.SameSiteLaxMode, Expires: time.Unix(s.Exp, 0)})
}
func (a *App) readSession(r *http.Request) (SessionClaims, bool) {
	c, err := r.Cookie(a.cfg.WebSessionCookie)
	if err != nil {
		return SessionClaims{}, false
	}
	parts := strings.Split(c.Value, ".")
	if len(parts) != 2 {
		return SessionClaims{}, false
	}
	b, err := base64.RawURLEncoding.DecodeString(parts[0])
	if err != nil {
		return SessionClaims{}, false
	}
	if !hmac.Equal([]byte(parts[1]), []byte(a.signBytes(b))) {
		return SessionClaims{}, false
	}
	var s SessionClaims
	if json.Unmarshal(b, &s) != nil || s.Exp < time.Now().Unix() {
		return SessionClaims{}, false
	}
	if !a.validAdminID(s.AdminID) {
		return SessionClaims{}, false
	}
	return s, true
}
func (a *App) csrf(r *http.Request) string {
	if s, ok := a.readSession(r); ok {
		return html.EscapeString(s.CSRF)
	}
	return ""
}
func (a *App) checkCSRF(r *http.Request) bool {
	s, ok := a.readSession(r)
	if !ok {
		return false
	}
	_ = r.ParseForm()
	got := r.FormValue("csrf_token")
	if got == "" {
		got = r.Header.Get("X-CSRF-Token")
	}
	return hmac.Equal([]byte(got), []byte(s.CSRF))
}
func (a *App) currentAdminID(r *http.Request) int64 {
	if s, ok := a.readSession(r); ok {
		return s.AdminID
	}
	return a.defaultAdminID()
}

// ---------------- Admin data helpers ----------------
func (a *App) webCounts() map[string]int64 {
	counts := map[string]int64{"users": 0, "schedules": 0, "blocked": 0, "api_keys": 0}
	counts["users"] = a.tableCount("user_prefs", "user_id")
	counts["schedules"] = a.tableCount("scheduled_broadcasts", "id")
	counts["blocked"] = a.tableCount("blocked_users", "user_id")
	counts["api_keys"] = a.tableCount("ai_api_keys", "id")
	return counts
}
func (a *App) tableCount(table, col string) int64 {
	var rows []map[string]any
	err := a.supabaseGet(table, url.Values{"select": {col}, "limit": {"10000"}}, &rows)
	if err != nil {
		return 0
	}
	return int64(len(rows))
}
func (a *App) fetchBotSettings(force bool) map[string]string {
	a.mu.RLock()
	if !force && time.Since(a.settingsTS) < 30*time.Second {
		out := copyMap(a.settings)
		a.mu.RUnlock()
		return out
	}
	a.mu.RUnlock()
	out := copyMap(botSettingDefaults)
	var rows []BotSettingRow
	if a.supabaseGet("bot_settings", url.Values{"select": {"key,value"}}, &rows) == nil {
		for _, r := range rows {
			if _, ok := botSettingDefaults[r.Key]; ok {
				out[r.Key] = r.Value
			}
		}
	}
	a.mu.Lock()
	a.settings = copyMap(out)
	a.settingsTS = time.Now()
	a.mu.Unlock()
	return out
}
func (a *App) setBotSetting(key, value string, adminID int64) {
	if _, ok := botSettingDefaults[key]; !ok {
		return
	}
	row := BotSettingRow{Key: key, Value: value, UpdatedBy: adminID, UpdatedAt: time.Now().UTC().Format(time.RFC3339Nano)}
	_ = a.supabaseUpsert("bot_settings", row, "key", nil)
	a.mu.Lock()
	a.settings[key] = value
	a.settingsTS = time.Time{}
	a.mu.Unlock()
}
func (a *App) setBlocked(userID, adminID int64, blocked bool, reason string) {
	a.mu.Lock()
	if blocked {
		a.blocked[userID] = true
	} else {
		delete(a.blocked, userID)
	}
	a.blockedTS[userID] = time.Now()
	a.mu.Unlock()
	if blocked {
		_ = a.supabaseUpsert("blocked_users", map[string]any{"user_id": userID, "admin_id": adminID, "reason": reason, "blocked_at": time.Now().UTC().Format(time.RFC3339Nano)}, "user_id", nil)
	} else {
		_, _ = a.supabaseDelete("blocked_users", url.Values{"user_id": {"eq." + strconv.FormatInt(userID, 10)}}, nil), reason
	}
}
func (a *App) isBlocked(userID int64) bool {
	a.mu.RLock()
	b, ok := a.blocked[userID]
	ts := a.blockedTS[userID]
	a.mu.RUnlock()
	if ok && time.Since(ts) < 60*time.Second {
		return b
	}
	var rows []map[string]any
	err := a.supabaseGet("blocked_users", url.Values{"select": {"user_id"}, "user_id": {"eq." + strconv.FormatInt(userID, 10)}, "limit": {"1"}}, &rows)
	blocked := err == nil && len(rows) > 0
	a.mu.Lock()
	if blocked {
		a.blocked[userID] = true
	} else {
		delete(a.blocked, userID)
	}
	a.blockedTS[userID] = time.Now()
	a.mu.Unlock()
	return blocked
}
func (a *App) insertSchedule(adminID int64, photoFileID, caption, plainText *string, broadcastAt time.Time, draft bool) (ScheduleRow, error) {
	errMsg := (*string)(nil)
	if draft {
		m := schedDraftMarker
		errMsg = &m
	}
	row := ScheduleRow{AdminID: adminID, PhotoFileID: photoFileID, Caption: caption, PlainText: plainText, BroadcastAt: broadcastAt.UTC().Format(time.RFC3339Nano), Status: "pending", ErrorMsg: errMsg}
	var rows []ScheduleRow
	err := a.supabaseInsert("scheduled_broadcasts", row, &rows)
	if err != nil {
		return row, err
	}
	if len(rows) > 0 {
		return rows[0], nil
	}
	return row, nil
}
func (a *App) confirmSchedule(id, adminID int64) bool {
	var rows []ScheduleRow
	err := a.supabasePatch("scheduled_broadcasts", url.Values{"id": {"eq." + strconv.FormatInt(id, 10)}, "admin_id": {"eq." + strconv.FormatInt(adminID, 10)}, "status": {"eq.pending"}, "error_msg": {"eq." + schedDraftMarker}}, map[string]any{"error_msg": nil}, &rows)
	return err == nil && len(rows) > 0
}
func (a *App) setScheduleStatus(id int64, status, msg string) bool {
	var ptr *string
	if msg != "" {
		ptr = &msg
	}
	var rows []ScheduleRow
	err := a.supabasePatch("scheduled_broadcasts", url.Values{"id": {"eq." + strconv.FormatInt(id, 10)}}, map[string]any{"status": status, "error_msg": ptr}, &rows)
	return err == nil && len(rows) > 0
}

// ---------------- Scheduler/broadcast ----------------
func (a *App) schedulerLoop(ctx context.Context) {
	ticker := time.NewTicker(20 * time.Second)
	defer ticker.Stop()
	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			a.fireDueSchedules()
		}
	}
}
func (a *App) fireDueSchedules() {
	if !a.acquireLock("scheduled_broadcasts", 90*time.Second) {
		return
	}
	defer a.releaseLock("scheduled_broadcasts")
	now := time.Now().UTC().Format(time.RFC3339Nano)
	var rows []ScheduleRow
	err := a.supabaseGet("scheduled_broadcasts", url.Values{"select": {"*"}, "status": {"eq.pending"}, "broadcast_at": {"lte." + now}, "order": {"broadcast_at.asc"}, "limit": {"10"}}, &rows)
	if err != nil {
		return
	}
	for _, row := range rows {
		if row.ErrorMsg != nil && strings.TrimSpace(*row.ErrorMsg) != "" {
			continue
		}
		a.claimAndSendSchedule(row)
	}
}
func (a *App) claimAndSendSchedule(row ScheduleRow) {
	marker := "sending_started_at=" + time.Now().UTC().Format(time.RFC3339Nano)
	var claimed []ScheduleRow
	err := a.supabasePatch("scheduled_broadcasts", url.Values{"id": {"eq." + strconv.FormatInt(row.ID, 10)}, "status": {"eq.pending"}}, map[string]any{"status": "sending", "error_msg": marker}, &claimed)
	if err != nil || len(claimed) == 0 {
		return
	}
	sent, failed, blocked := a.broadcastSchedule(row)
	status := "done"
	var msg *string
	if failed > 0 && sent == 0 {
		status = "failed"
		m := "all sends failed"
		msg = &m
	}
	_ = a.supabasePatch("scheduled_broadcasts", url.Values{"id": {"eq." + strconv.FormatInt(row.ID, 10)}}, map[string]any{"status": status, "sent_count": sent, "failed_count": failed, "blocked_count": blocked, "error_msg": msg}, nil)
}
func (a *App) broadcastSchedule(row ScheduleRow) (int64, int64, int64) {
	text := valString(row.PlainText)
	caption := valString(row.Caption)
	return a.broadcastToAll(text, valString(row.PhotoFileID), caption)
}
func (a *App) broadcastTextToAll(text string) {
	sent, failed, blocked := a.broadcastToAll(text, "", "")
	log.Printf("broadcast done sent=%d failed=%d blocked=%d", sent, failed, blocked)
}
func (a *App) broadcastToAll(text, photoFileID, caption string) (int64, int64, int64) {
	ids := a.getAllUserIDs()
	sem := make(chan struct{}, a.cfg.MaxConcurrentBroadcast)
	var wg sync.WaitGroup
	var mu sync.Mutex
	var sent, failed, blocked int64
	for _, id := range ids {
		if a.isBlocked(id) {
			blocked++
			continue
		}
		wg.Add(1)
		sem <- struct{}{}
		go func(uid int64) {
			defer wg.Done()
			defer func() { <-sem }()
			var err error
			if photoFileID != "" {
				err = a.telegramSendPhoto(uid, photoFileID, caption)
			} else {
				err = a.telegramSendMessage(uid, text, "")
			}
			mu.Lock()
			if err != nil {
				failed++
			} else {
				sent++
			}
			mu.Unlock()
			time.Sleep(a.cfg.BroadcastDelay)
		}(id)
	}
	wg.Wait()
	return sent, failed, blocked
}
func (a *App) getAllUserIDs() []int64 {
	var rows []UserPref
	_ = a.supabaseGet("user_prefs", url.Values{"select": {"user_id"}, "limit": {"10000"}}, &rows)
	ids := make([]int64, 0, len(rows))
	for _, r := range rows {
		if r.UserID != 0 {
			ids = append(ids, r.UserID)
		}
	}
	return ids
}
func (a *App) acquireLock(key string, ttl time.Duration) bool {
	if a.cfg.SupabaseURL == "" || a.cfg.SupabaseKey == "" {
		return true
	}
	now := time.Now().UTC()
	until := now.Add(ttl).Format(time.RFC3339Nano)
	nowStr := now.Format(time.RFC3339Nano)
	patch := map[string]any{"owner": a.owner, "locked_until": until, "updated_at": nowStr}
	var rows []LockRow
	if a.supabasePatch("bot_locks", url.Values{"lock_key": {"eq." + key}, "owner": {"eq." + a.owner}}, patch, &rows) == nil && len(rows) > 0 {
		return true
	}
	if a.supabasePatch("bot_locks", url.Values{"lock_key": {"eq." + key}, "locked_until": {"lt." + nowStr}}, patch, &rows) == nil && len(rows) > 0 {
		return true
	}
	err := a.supabaseInsert("bot_locks", LockRow{LockKey: key, Owner: a.owner, LockedUntil: until, UpdatedAt: nowStr}, &rows)
	return err == nil
}
func (a *App) releaseLock(key string) bool {
	if a.cfg.SupabaseURL == "" || a.cfg.SupabaseKey == "" {
		return true
	}
	var rows []LockRow
	err := a.supabaseDelete("bot_locks", url.Values{"lock_key": {"eq." + key}, "owner": {"eq." + a.owner}}, &rows)
	return err == nil
}

// ---------------- Telegram ----------------
func (a *App) telegramWebhook(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", 405)
		return
	}
	if a.cfg.TelegramWebhookSecret != "" && r.Header.Get("X-Telegram-Bot-Api-Secret-Token") != a.cfg.TelegramWebhookSecret {
		http.Error(w, "unauthorized", 401)
		return
	}
	var upd TGUpdate
	if err := json.NewDecoder(io.LimitReader(r.Body, 8<<20)).Decode(&upd); err != nil {
		http.Error(w, "bad update", 400)
		return
	}
	go a.handleTelegramUpdate(upd)
	writeJSON(w, 200, map[string]bool{"ok": true})
}
func (a *App) telegramPollingLoop(ctx context.Context) {
	log.Printf("Telegram long polling started")
	for {
		select {
		case <-ctx.Done():
			return
		default:
		}
		updates, err := a.telegramGetUpdates(a.updateID+1, 30)
		if err != nil {
			log.Printf("getUpdates error: %v", err)
			time.Sleep(3 * time.Second)
			continue
		}
		for _, upd := range updates {
			if upd.UpdateID > a.updateID {
				a.updateID = upd.UpdateID
			}
			a.handleTelegramUpdate(upd)
		}
	}
}
func (a *App) handleTelegramUpdate(upd TGUpdate) {
	if upd.Message != nil {
		a.handleTelegramMessage(upd.Message)
		return
	}
	if upd.CallbackQuery != nil {
		_ = a.telegramAnswerCallback(upd.CallbackQuery.ID, "OK")
	}
}
func (a *App) handleTelegramMessage(m *TGMessage) {
	if m.From == nil {
		return
	}
	a.syncUserData(*m.From)
	if a.isBlocked(m.From.ID) {
		a.metricInc("blocked_hits", 1)
		return
	}
	text := strings.TrimSpace(m.Text)
	if strings.HasPrefix(text, "/") {
		a.handleCommand(m, text)
		return
	}
	settings := a.fetchBotSettings(false)
	if settingBool(settings, "maintenance_mode", false) && !a.validAdminID(m.From.ID) {
		_ = a.telegramSendMessage(m.Chat.ID, "🛠️ Bot is under maintenance. Please try again later.", "")
		return
	}
	if len(m.Photo) > 0 && settingBool(settings, "ocr_enabled", true) {
		a.handlePhoto(m)
		return
	}
	if text != "" && settingBool(settings, "tts_enabled", true) {
		a.handleUserText(m, text)
		return
	}
}
func (a *App) handleCommand(m *TGMessage, text string) {
	cmd := strings.Fields(text)
	name := strings.Split(strings.TrimPrefix(cmd[0], "/"), "@")[0]
	switch name {
	case "start":
		_ = a.telegramSendMessage(m.Chat.ID, "សួស្តី! Send text for voice/AI, or send a photo for OCR.\n\nHello! Send text for voice/AI, or send a photo for OCR.", "")
	case "help":
		_ = a.telegramSendMessage(m.Chat.ID, "Commands: /start /help /myprefs /clear /admin /api", "")
	case "myprefs":
		_ = a.telegramSendMessage(m.Chat.ID, "Prefs: gender/speed are stored in Supabase user_prefs.", "")
	case "clear":
		_ = a.supabaseDelete("conversation_history", url.Values{"user_id": {"eq." + strconv.FormatInt(m.From.ID, 10)}}, nil)
		_ = a.telegramSendMessage(m.Chat.ID, "History cleared.", "")
	case "admin":
		if a.validAdminID(m.From.ID) {
			_ = a.telegramSendMessage(m.Chat.ID, a.adminText(), "HTML")
		} else {
			_ = a.telegramSendMessage(m.Chat.ID, "Admin only.", "")
		}
	case "api":
		if a.validAdminID(m.From.ID) {
			a.handleAPICommand(m, cmd)
		} else {
			_ = a.telegramSendMessage(m.Chat.ID, "Admin only.", "")
		}
	case "broadcast":
		if a.validAdminID(m.From.ID) {
			msg := strings.TrimSpace(strings.TrimPrefix(text, cmd[0]))
			if msg != "" {
				go a.broadcastTextToAll(msg)
				_ = a.telegramSendMessage(m.Chat.ID, "Broadcast started.", "")
			} else {
				_ = a.telegramSendMessage(m.Chat.ID, "Usage: /broadcast your message", "")
			}
		}
	default:
		_ = a.telegramSendMessage(m.Chat.ID, "Unknown command. Use /help", "")
	}
}
func (a *App) handleAPICommand(m *TGMessage, fields []string) {
	if len(fields) >= 2 && fields[1] == "create" {
		note := ""
		if len(fields) > 2 {
			note = strings.Join(fields[2:], " ")
		}
		raw, _, store, err := a.createAPIKey(m.From.ID, note)
		if err != nil {
			_ = a.telegramSendMessage(m.Chat.ID, "API key create failed: "+err.Error(), "")
			return
		}
		_ = a.telegramSendMessage(m.Chat.ID, "✅ New API key (copy now):\n<code>"+html.EscapeString(raw)+"</code>\nStore: "+store, "HTML")
		return
	}
	if len(fields) >= 2 && fields[1] == "list" {
		rows := a.listAPIKeys(20)
		var b strings.Builder
		b.WriteString("🔑 API Keys\n")
		for _, r := range rows {
			b.WriteString(fmt.Sprintf("%d %s active=%v\n", r.ID, r.KeyPrefix, r.Active && r.RevokedAt == nil))
		}
		_ = a.telegramSendMessage(m.Chat.ID, b.String(), "")
		return
	}
	if len(fields) >= 3 && fields[1] == "revoke" {
		ok, msg := a.revokeAPIKey(fields[2])
		if ok {
			_ = a.telegramSendMessage(m.Chat.ID, "Revoked: "+msg, "")
		} else {
			_ = a.telegramSendMessage(m.Chat.ID, msg, "")
		}
		return
	}
	_ = a.telegramSendMessage(m.Chat.ID, "/api create [note]\n/api list\n/api revoke <id-or-prefix>", "")
}
func (a *App) handlePhoto(m *TGMessage) {
	best := m.Photo[0]
	for _, p := range m.Photo {
		if p.FileSize > best.FileSize || p.Width*p.Height > best.Width*best.Height {
			best = p
		}
	}
	data, mime, err := a.telegramDownloadFile(best.FileID)
	if err != nil {
		_ = a.telegramSendMessage(m.Chat.ID, "OCR download failed: "+err.Error(), "")
		return
	}
	text, provider, model, err := a.askOCRImage(data, mime)
	if err != nil {
		_ = a.telegramSendMessage(m.Chat.ID, "OCR failed: "+err.Error(), "")
		return
	}
	a.metricInc("ocr", 1)
	_ = provider
	_ = model
	if text == "" {
		text = "No text found."
	}
	for _, page := range paginatePlain(text, telegramMessageLimit) {
		_ = a.telegramSendMessage(m.Chat.ID, page, "")
	}
}
func (a *App) handleUserText(m *TGMessage, text string) {
	_ = a.saveTextCache(m.Chat.ID, m.MessageID, m.From.ID, m.From.Username, text)
	_ = a.appendHistory(m.From.ID, "user", text)
	if path, err := a.generateVoice(text); err == nil && path != "" {
		defer os.Remove(path)
		if err := a.telegramSendAudioFile(m.Chat.ID, path, "voice.mp3"); err == nil {
			a.metricInc("tts", 1)
			return
		}
	}
	reply, _, _, err := a.aiTextReply(text, nil)
	if err != nil || reply == "" {
		reply = text
	}
	_ = a.appendHistory(m.From.ID, "assistant", reply)
	for _, page := range paginatePlain(reply, telegramMessageLimit) {
		_ = a.telegramSendMessage(m.Chat.ID, page, "")
	}
}
func (a *App) generateVoice(text string) (string, error) {
	bin := a.cfg.EdgeTTSBin
	if bin == "" {
		return "", errors.New("EDGE_TTS_BIN not set")
	}
	if _, err := exec.LookPath(bin); err != nil {
		return "", err
	}
	out := filepath.Join(os.TempDir(), "gobot_tts_"+randomToken(8)+".mp3")
	voice := "en-US-JennyNeural"
	if detectLang(text) == "km" {
		voice = envStr("EDGE_TTS_KM_VOICE", voice)
	} else {
		voice = envStr("EDGE_TTS_EN_VOICE", voice)
	}
	ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
	defer cancel()
	cmd := exec.CommandContext(ctx, bin, "--voice", voice, "--text", text, "--write-media", out)
	if data, err := cmd.CombinedOutput(); err != nil {
		os.Remove(out)
		return "", fmt.Errorf("edge-tts failed: %v %s", err, string(data))
	}
	return out, nil
}
