func (a *App) telegramAPI(method string, payload any, out any) error {
	if a.cfg.TelegramBotToken == "" {
		return errors.New("TELEGRAM_BOT_TOKEN missing")
	}
	var body io.Reader
	contentType := "application/json"
	if payload != nil {
		b, _ := json.Marshal(payload)
		body = bytes.NewReader(b)
	}
	req, _ := http.NewRequest("POST", "https://api.telegram.org/bot"+a.cfg.TelegramBotToken+"/"+method, body)
	req.Header.Set("Content-Type", contentType)
	resp, err := a.client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()
	data, _ := io.ReadAll(io.LimitReader(resp.Body, 16<<20))
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fmt.Errorf("telegram %s HTTP %d: %s", method, resp.StatusCode, string(data))
	}
	if out != nil {
		return json.Unmarshal(data, out)
	}
	return nil
}
func (a *App) telegramSendMessage(chatID int64, text, parseMode string) error {
	if text == "" {
		return nil
	}
	p := map[string]any{"chat_id": chatID, "text": text}
	if parseMode != "" {
		p["parse_mode"] = parseMode
	}
	return a.telegramAPI("sendMessage", p, nil)
}
func (a *App) telegramSendPhoto(chatID int64, fileID, caption string) error {
	p := map[string]any{"chat_id": chatID, "photo": fileID}
	if caption != "" {
		p["caption"] = caption
	}
	return a.telegramAPI("sendPhoto", p, nil)
}
func (a *App) telegramAnswerCallback(id, text string) error {
	return a.telegramAPI("answerCallbackQuery", map[string]any{"callback_query_id": id, "text": text}, nil)
}
func (a *App) telegramGetUpdates(offset int64, timeout int) ([]TGUpdate, error) {
	var raw struct {
		OK          bool       `json:"ok"`
		Result      []TGUpdate `json:"result"`
		Description string     `json:"description"`
	}
	err := a.telegramAPI("getUpdates", map[string]any{"offset": offset, "timeout": timeout, "allowed_updates": []string{"message", "callback_query"}}, &raw)
	if err != nil {
		return nil, err
	}
	if !raw.OK {
		return nil, errors.New(raw.Description)
	}
	return raw.Result, nil
}
func (a *App) telegramDownloadFile(fileID string) ([]byte, string, error) {
	var raw struct {
		OK     bool `json:"ok"`
		Result struct {
			FilePath string `json:"file_path"`
		} `json:"result"`
		Description string `json:"description"`
	}
	if err := a.telegramAPI("getFile", map[string]any{"file_id": fileID}, &raw); err != nil {
		return nil, "", err
	}
	if !raw.OK {
		return nil, "", errors.New(raw.Description)
	}
	u := "https://api.telegram.org/file/bot" + a.cfg.TelegramBotToken + "/" + raw.Result.FilePath
	resp, err := a.client.Get(u)
	if err != nil {
		return nil, "", err
	}
	defer resp.Body.Close()
	data, err := io.ReadAll(io.LimitReader(resp.Body, maxImageBytes+1))
	if err != nil {
		return nil, "", err
	}
	mime := http.DetectContentType(data)
	return data, mime, nil
}
func (a *App) telegramSendAudioFile(chatID int64, path, name string) error {
	if a.cfg.TelegramBotToken == "" {
		return errors.New("TELEGRAM_BOT_TOKEN missing")
	}
	f, err := os.Open(path)
	if err != nil {
		return err
	}
	defer f.Close()
	var buf bytes.Buffer
	mw := multipart.NewWriter(&buf)
	_ = mw.WriteField("chat_id", strconv.FormatInt(chatID, 10))
	part, err := mw.CreateFormFile("audio", name)
	if err != nil {
		return err
	}
	if _, err = io.Copy(part, f); err != nil {
		return err
	}
	mw.Close()
	req, _ := http.NewRequest("POST", "https://api.telegram.org/bot"+a.cfg.TelegramBotToken+"/sendAudio", &buf)
	req.Header.Set("Content-Type", mw.FormDataContentType())
	resp, err := a.client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()
	data, _ := io.ReadAll(io.LimitReader(resp.Body, 4<<20))
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fmt.Errorf("sendAudio HTTP %d: %s", resp.StatusCode, string(data))
	}
	return nil
}

// ---------------- Mini Redis client (GET/SET/DEL JSON cache support) ----------------
type MiniRedis struct {
	addr, username, password string
	tls                      bool
	mu                       sync.Mutex
}

func NewMiniRedis(raw string) (*MiniRedis, error) {
	u, err := url.Parse(raw)
	if err != nil {
		return nil, err
	}
	host := u.Host
	if host == "" {
		return nil, errors.New("missing redis host")
	}
	user := ""
	pass := ""
	if u.User != nil {
		user = u.User.Username()
		pass, _ = u.User.Password()
	}
	return &MiniRedis{addr: host, username: user, password: pass, tls: u.Scheme == "rediss"}, nil
}
func (r *MiniRedis) command(args ...string) (string, error) {
	r.mu.Lock()
	defer r.mu.Unlock()
	var conn net.Conn
	var err error
	d := net.Dialer{Timeout: 5 * time.Second}
	if r.tls {
		conn, err = tls.DialWithDialer(&d, "tcp", r.addr, &tls.Config{MinVersion: tls.VersionTLS12})
	} else {
		conn, err = d.Dial("tcp", r.addr)
	}
	if err != nil {
		return "", err
	}
	defer conn.Close()
	_ = conn.SetDeadline(time.Now().Add(8 * time.Second))
	if r.password != "" {
		auth := []string{"AUTH"}
		if r.username != "" {
			auth = append(auth, r.username)
		}
		auth = append(auth, r.password)
		if _, err := redisSend(conn, auth...); err != nil {
			return "", err
		}
	}
	return redisSend(conn, args...)
}
func redisSend(wr io.ReadWriter, args ...string) (string, error) {
	var b strings.Builder
	b.WriteString("*")
	b.WriteString(strconv.Itoa(len(args)))
	b.WriteString("\r\n")
	for _, a := range args {
		b.WriteString("$")
		b.WriteString(strconv.Itoa(len(a)))
		b.WriteString("\r\n")
		b.WriteString(a)
		b.WriteString("\r\n")
	}
	if _, err := io.WriteString(wr, b.String()); err != nil {
		return "", err
	}
	return redisRead(wr)
}
func redisRead(r io.Reader) (string, error) {
	one := make([]byte, 1)
	if _, err := io.ReadFull(r, one); err != nil {
		return "", err
	}
	line, err := readLine(r)
	if err != nil {
		return "", err
	}
	switch one[0] {
	case '+', ':':
		return line, nil
	case '-':
		return "", errors.New(line)
	case '$':
		n, _ := strconv.Atoi(line)
		if n < 0 {
			return "", nil
		}
		buf := make([]byte, n+2)
		_, err := io.ReadFull(r, buf)
		if err != nil {
			return "", err
		}
		return string(buf[:n]), nil
	default:
		return "", fmt.Errorf("unknown redis response %q", one[0])
	}
}
func readLine(r io.Reader) (string, error) {
	var b []byte
	tmp := make([]byte, 1)
	for {
		_, err := io.ReadFull(r, tmp)
		if err != nil {
			return "", err
		}
		if tmp[0] == '\r' {
			_, err = io.ReadFull(r, tmp)
			return string(b), err
		}
		b = append(b, tmp[0])
	}
}

// ---------------- General helpers ----------------
func envStr(k, d string) string {
	if v := os.Getenv(k); v != "" {
		return v
	}
	return d
}
func firstNonEmpty(v ...string) string {
	for _, s := range v {
		if s != "" {
			return s
		}
	}
	return ""
}
func envBool(k string, d bool) bool {
	v := strings.ToLower(strings.TrimSpace(os.Getenv(k)))
	if v == "" {
		return d
	}
	return v == "1" || v == "true" || v == "yes" || v == "on" || v == "y"
}
func envInt(k string, d, minv, maxv int) int {
	v, err := strconv.Atoi(strings.TrimSpace(os.Getenv(k)))
	if err != nil {
		v = d
	}
	if v < minv {
		v = minv
	}
	if v > maxv {
		v = maxv
	}
	return v
}
func envFloat(k string, d float64) float64 {
	v, err := strconv.ParseFloat(strings.TrimSpace(os.Getenv(k)), 64)
	if err != nil {
		return d
	}
	return v
}
func parseAdminIDs(raw string) map[int64]bool {
	out := map[int64]bool{}
	for _, p := range regexp.MustCompile(`[\s,;]+`).Split(raw, -1) {
		if p == "" {
			continue
		}
		if id, err := strconv.ParseInt(p, 10, 64); err == nil {
			out[id] = true
		}
	}
	return out
}
func randomToken(n int) string {
	if n <= 0 {
		n = 16
	}
	b := make([]byte, n)
	_, _ = rand.Read(b)
	return base64.RawURLEncoding.EncodeToString(b)
}
func writeJSON(w http.ResponseWriter, code int, v any) {
	w.Header().Set("Content-Type", "application/json; charset=utf-8")
	w.WriteHeader(code)
	_ = json.NewEncoder(w).Encode(v)
}
func detectLang(text string) string {
	kh := 0
	alpha := 0
	for _, r := range text {
		if r >= '\u1780' && r <= '\u17FF' {
			kh++
		}
		if (r >= 'A' && r <= 'Z') || (r >= 'a' && r <= 'z') || (r >= '\u1780' && r <= '\u17FF') {
			alpha++
		}
	}
	if alpha > 0 && float64(kh)/float64(alpha) > 0.25 {
		return "km"
	}
	return "en"
}
func keysBool(m map[string]bool) []string {
	out := make([]string, 0, len(m))
	for k := range m {
		out = append(out, k)
	}
	sort.Strings(out)
	return out
}
func parseInt(s string, d int) int {
	v, err := strconv.Atoi(strings.TrimSpace(s))
	if err != nil {
		return d
	}
	return v
}
func parseInt64(s string, d int64) int64 {
	v, err := strconv.ParseInt(strings.TrimSpace(s), 10, 64)
	if err != nil {
		return d
	}
	return v
}
func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}
func valString(p *string) string {
	if p == nil {
		return ""
	}
	return *p
}
func copyMap(m map[string]string) map[string]string {
	out := make(map[string]string, len(m))
	for k, v := range m {
		out[k] = v
	}
	return out
}
func settingBool(m map[string]string, key string, d bool) bool {
	raw := strings.ToLower(strings.TrimSpace(m[key]))
	if raw == "" {
		if d {
			return true
		}
		return false
	}
	return raw == "1" || raw == "true" || raw == "yes" || raw == "on" || raw == "enabled"
}
func paginatePlain(text string, limit int) []string {
	text = strings.TrimSpace(text)
	if text == "" {
		return nil
	}
	var pages []string
	for len(text) > limit {
		cut := strings.LastIndex(text[:limit], "\n")
		if cut <= 0 {
			cut = limit
		}
		pages = append(pages, text[:cut])
		text = strings.TrimSpace(text[cut:])
	}
	if text != "" {
		pages = append(pages, text)
	}
	return pages
}
func (a *App) metricInc(k string, n int64) { a.mu.Lock(); a.metrics[k] += n; a.mu.Unlock() }
func (a *App) metricsSnapshot() map[string]int64 {
	a.mu.RLock()
	defer a.mu.RUnlock()
	out := make(map[string]int64, len(a.metrics))
	for k, v := range a.metrics {
		out[k] = v
	}
	return out
}
func (a *App) uptime() string {
	sec := int(time.Since(a.start).Seconds())
	d := sec / 86400
	sec %= 86400
	h := sec / 3600
	sec %= 3600
	m := sec / 60
	if d > 0 {
		return fmt.Sprintf("%dd %dh %dm", d, h, m)
	}
	if h > 0 {
		return fmt.Sprintf("%dh %dm", h, m)
	}
	return fmt.Sprintf("%dm", m)
}
func (a *App) fmtLocal(t time.Time) string {
	return t.In(a.cfg.AppLocation).Format("2006-01-02 03:04 PM ") + a.cfg.TimezoneAlias + " (" + a.cfg.TimezoneUTCLabel + ")"
}
func (a *App) timeHint() string {
	return "Phnom Penh local time — AM/PM, " + a.cfg.TimezoneAlias + " (" + a.cfg.TimezoneUTCLabel + ")"
}
func (a *App) parseLocalSchedule(raw string) (time.Time, error) {
	raw = strings.TrimSpace(raw)
	layouts := []string{"2006-01-02T15:04", "2006-01-02 03:04 PM", "2006-01-02 15:04", "2006-01-02 03:04PM"}
	var last error
	for _, layout := range layouts {
		dt, err := time.ParseInLocation(layout, raw, a.cfg.AppLocation)
		if err == nil {
			return dt.UTC(), nil
		}
		last = err
	}
	return time.Time{}, last
}
func (a *App) fmtMaybeTime(raw string) string {
	if raw == "" {
		return ""
	}
	if t, err := time.Parse(time.RFC3339Nano, raw); err == nil {
		return a.fmtLocal(t)
	}
	if t, err := time.Parse(time.RFC3339, raw); err == nil {
		return a.fmtLocal(t)
	}
	return raw
}
func (a *App) short(s string, n int) string {
	s = strings.Join(strings.Fields(s), " ")
	if len([]rune(s)) <= n {
		return s
	}
	r := []rune(s)
	return string(r[:n-1]) + "…"
}
func (a *App) webStatusBadge(status string, errMsg *string) string {
	if errMsg != nil && *errMsg == schedDraftMarker {
		return "preview"
	}
	if status == "" {
		return "unknown"
	}
	return status
}
func (a *App) systemSummary() string {
	return fmt.Sprintf("Supabase: %v\nRedis: %v\nHF: %v\nGemini: %v\nTelegram: %v\nUptime: %s", a.cfg.SupabaseURL != "" && a.cfg.SupabaseKey != "", a.redis != nil, a.cfg.HFToken != "", a.cfg.GeminiAPIKey != "", a.cfg.TelegramBotToken != "", a.uptime())
}
func (a *App) startupSelfCheck() {
	var checks []string
	if a.cfg.TelegramBotToken == "" {
		checks = append(checks, "TELEGRAM_BOT_TOKEN is missing")
	}
	if len(a.cfg.AdminIDs) == 0 {
		checks = append(checks, "ADMIN_IDS is empty")
	}
	if a.cfg.WebAdminPassword == "" && a.cfg.WebAdminEnabled {
		checks = append(checks, "ADMIN_WEB_PASSWORD / WEB_ADMIN_PASSWORD is missing")
	}
	if a.cfg.SupabaseURL == "" || a.cfg.SupabaseKey == "" {
		checks = append(checks, "Supabase URL/key missing")
	}
	if a.cfg.HFToken == "" {
		checks = append(checks, "HF_TOKEN is missing")
	}
	if a.cfg.RedisURL == "" {
		checks = append(checks, "REDIS_URL is missing; cache fallback uses memory/Supabase")
	}
	if len(checks) > 0 {
		log.Printf("Startup self-check warnings:\n- %s", strings.Join(checks, "\n- "))
	} else {
		log.Printf("Startup self-check passed")
	}
}
func activeClass(active, key string) string {
	if active == key {
		return "active"
	}
	return ""
}
func onOff(b bool) string {
	if b {
		return "ON"
	}
	return "OFF"
}
